int main(){int T; if(scanf("%d",&T)!=1) return 0; while(T--){uint32_t N; scanf("%u",&N); uint32_t p=highestPowerOfTwo(N); uint32_t len1=N-p+1; uint32_t len2=p/2; printf("%u\n", len1>len2?len1:len2);} return 0; }

