code.Java:
import java.io.*;
import java.util.*;
public class Main{
    private static long highestPowerOfTwo(long n){int msb=63-Long.numberOfLeadingZeros(n);return 1L<<msb;}
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb=new StringBuilder();
        int T=Integer.parseInt(br.readLine().trim());
        for(int i=0;i<T;i++){
            long N=Long.parseLong(br.readLine().trim());
            long p=highestPowerOfTwo(N);
            long len1=N-p+1;
            long len2=p/2;
            sb.append(Math.max(len1,len2)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys
def highest_power_of_two(n):
    return 1 << (n.bit_length()-1)

def solve():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        N=int(next(it))
        p=highest_power_of_two(N)
        len1=N-p+1
        len2=p//2
        out.append(str(max(len1,len2)))
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

